// n8n Code node — Build Apollo Mixed People Search POST body
// Target: Hiring Managers, Recruiters, Talent Acquisition
// Updated to work with domain field in output object

// 1) Inputs
const items = $input.all();

// 2) Input validation
if (!items || items.length === 0) {
  return [{ json: { error: 'No input items received' } }];
}

// 3) Extract and clean domains from output.domain field
const allDomains = Array.from(new Set(
  items
    .map(item => {
      // Access domain from nested output object
      const domain = String(item.json?.output?.domain || '').trim().toLowerCase();

      if (!domain) return '';

      // Clean domain - remove protocol, www, paths
      let cleanDomain = domain
        .replace(/^https?:\/\//i, '')  // Remove protocol
        .replace(/^www\./, '')          // Remove www.
        .split('/')[0]                  // Get domain only (remove paths)
        .split('?')[0]                  // Remove query params
        .split('#')[0]                  // Remove anchors
        .trim();

      return cleanDomain;
    })
    .filter(d => {
      // Filter out empty strings and invalid domains
      if (!d) return false;

      // Must have at least one dot and valid domain structure
      const domainRegex = /^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?(\.[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?)*\.[a-z]{2,}$/i;
      return domainRegex.test(d);
    })
));

// 4) Filter out unwanted domains (like linkedin.com from job postings)
const excludedDomains = ['linkedin.com', 'indeed.com', 'glassdoor.com', 'monster.com'];
const validDomains = allDomains.filter(d => !excludedDomains.includes(d));

// 5) Guard clause
if (validDomains.length === 0) {
  return [{ 
    json: { 
      error: 'No valid domains found',
      totalProcessed: items.length,
      domainsExtracted: allDomains.length,
      domainsExcluded: allDomains.length - validDomains.length
    } 
  }];
}

// 6) Hiring & Recruiting Titles
const titles = [
  // Talent Acquisition Leadership
  'VP of Talent Acquisition',
  'Vice President Talent Acquisition',
  'VP Talent Acquisition',
  'Director of Talent Acquisition',
  'Talent Acquisition Director',
  'Head of Talent Acquisition',
  'Head of Recruiting',

  // Recruiting Leadership
  'VP of Recruiting',
  'Vice President Recruiting',
  'Director of Recruiting',
  'Recruiting Director',
  'Director of Recruitment',
  'Recruitment Director',

  // HR Leadership (often involved in hiring)
  'VP of Human Resources',
  'VP Human Resources',
  'Director of Human Resources',
  'HR Director',
  'Head of HR',
  'Head of People',
  'Director of People',
  'People Director',

  // Chief Level
  'Chief Human Resources Officer',
  'CHRO',
  'Chief People Officer',
  'CPO',
  'Chief Talent Officer',

  // Senior Recruiters
  'Senior Recruiter',
  'Lead Recruiter',
  'Senior Talent Acquisition Partner',
  'Principal Recruiter',
  'Recruiting Manager',
  'Talent Acquisition Manager',
  'Talent Acquisition Lead',

  // Hiring Manager Titles
  'Hiring Manager',
  'Technical Recruiter',
  'Technical Recruiting Manager'
];

// 7) Build POST body for mixed_people/search
const body = {
  person_titles: titles,
  person_current_titles: titles,
  q_organization_domains_list: validDomains,
  page: 1,
  per_page: 10
};

// 8) Output for HTTP Request node with enhanced metadata
return [{
  json: {
    url: 'https://api.apollo.io/api/v1/mixed_people/search',
    method: 'POST',
    body,
    // Metadata for debugging
    metadata: {
      totalInputItems: items.length,
      domainsExtracted: allDomains.length,
      domainsExcluded: allDomains.length - validDomains.length,
      domainsUsed: validDomains.length,
      excludedDomainsList: allDomains.filter(d => excludedDomains.includes(d)),
      targetTitles: titles.length,
      targetCategory: 'Hiring Managers, Recruiters & Talent Acquisition'
    },
    // Full lists for verification
    processedDomains: validDomains,
    allExtractedDomains: allDomains,
    targetTitles: titles
  }
}];

// Get the input data
const inputData = $input.all();

// Extract people array from the nested structure
const data = inputData[0].json;
const people = data.people;

// Return each person as a separate item with flattened structure
return people.map(person => ({
  json: {
    // Person fields
    id: person.id,
    first_name: person.first_name,
    last_name_obfuscated: person.last_name_obfuscated,
    title: person.title,
    last_refreshed_at: person.last_refreshed_at,
    has_email: person.has_email,
    has_city: person.has_city,
    has_state: person.has_state,
    has_country: person.has_country,
    has_direct_phone: person.has_direct_phone,

    // Organization fields (flattened with org_ prefix)
    org_name: person.organization.name,
    org_has_industry: person.organization.has_industry,
    org_has_phone: person.organization.has_phone,
    org_has_city: person.organization.has_city,
    org_has_state: person.organization.has_state,
    org_has_country: person.organization.has_country,
    org_has_zip_code: person.organization.has_zip_code,
    org_has_revenue: person.organization.has_revenue,
    org_has_employee_count: person.organization.has_employee_count
  }
}));

// Get the input data
const inputData = $input.all();

// Process each item (person)
return inputData.map(item => {
  const person = item.json.person;
  const org = person.organization;

  return {
    json: {
      // Person Information
      person_id: person.id || null,
      first_name: person.first_name || null,
      last_name: person.last_name || null,
      full_name: person.name || null,
      email: person.email || null,
      email_status: person.email_status || null,

      // Social Links
      linkedin_url: person.linkedin_url || null,
      twitter_url: person.twitter_url || null,
      github_url: person.github_url || null,
      facebook_url: person.facebook_url || null,

      // Job Information
      title: person.title || null,
      headline: person.headline || null,
      seniority: person.seniority || null,
      departments: person.departments ? person.departments.join(', ') : null,
      functions: person.functions ? person.functions.join(', ') : null,

      // Location
      city: person.city || null,
      state: person.state || null,
      country: person.country || null,
      formatted_address: person.formatted_address || null,

      // Company Information
      company_id: org.id || null,
      company_name: org.name || null,
      company_website: org.website_url || null,
      company_linkedin: org.linkedin_url || null,
      company_phone: org.phone || null,
      company_industry: org.industry || null,
      company_employees: org.estimated_num_employees || null,
      company_revenue: org.organization_revenue_printed || null,
      company_founded_year: org.founded_year || null,
      company_description: org.short_description || null,

      // Company Location
      company_city: org.city || null,
      company_state: org.state || null,
      company_country: org.country || null,
      company_address: org.raw_address || null
    }
  };
});
